  tail: "secrets",
  visibility: "private",
  writers: { only: [contractNumericId] },  // numeric contract ID (not tail)
  readers: { only: [contractNumericId] },  // REQUIRED: omitting defaults to deny-all
  keyValidator: undefined,
};

await tenant.maps.create(mapInput);

// ============================================================================
