// executeControl() uses a control-plane function "map-entry-set"
// This bypasses normal ACL restrictions, allowing writes to read/write-locked maps
await tenant.executeControl("map-entry-set", {
  map_name: mapCanonicalName,    // NEVER hand-build z:<tid>:... — use canonicalName()
  key: "payment_token",
  value: process.env.PAYMENT_SECRET_VALUE!,
});

