// ============ Core Types (from @terminal3/t3n-sdk) ============

// 1. USER-TO-AGENT DELEGATION CREDENTIAL (User-signed mandate)
interface DelegationCredential {
  v: string;                                    // "ot3.delegation/1"
  user_did: string;                             // "did:t3n:<40-hex>"
  agent_pubkey: Uint8Array;                     // 33-byte compressed secp256k1
  org_did: string;                              // "did:t3n:<40-hex>"
  contract: string;                             // e.g. "tee:buyer-seller"
  functions: string[];                          // sorted, deduped, 1..=16 entries
  scopes: string[];                             // org-data scopes agent may read
  metadata: Record&lt;string, string&gt;;          // flat key-value labels (checked against grants)
  not_before_secs: bigint;                      // validity window start (unix seconds as string on wire)
  not_after_secs: bigint;                       // validity window end (unix seconds as string on wire)
  vc_id: Uint8Array;                            // random 16-byte credential id
}

// 2. ORG-SIDE GRANT RECORD (enforced via OrgDataClient)
interface UserGrant {
  user_did: string;                             // agent's DID
  functions: string[];                          // allowed function names
  scopes: string[];                             // org-data scope paths
  constraints: Record&lt;string, string&gt;;       // metadata matching (exact match required)
  expires_at_secs: number | null;               // unix timestamp, null = never expires
}

// 3. GRANT CONTAINER (read/written via OrgDataClient)
interface OrgContractGrants {
  contract_id: string;                          // e.g. "tee:buyer-seller"
  grants: UserGrant[];
}

// ============ BUILD &amp; SIGN THE CREDENTIAL (at org/user layer) ============

