// ===== TYPESCRIPT (Client-side): Reading audit events =====
// From SDK index.d.ts lines 973-1027:

interface AuditEvent {
    ts_ms: number;                    // Cluster-deterministic flush timestamp (ms)
    subject: string;                  // DID of user whose data was touched (host-stamped)
    actor: string;                    // DID of agent/user who acted (host-stamped)
    vc_id?: string | null;            // Delegation credential ID (null on self-call)
    action: string;                   // Contract-supplied: e.g. "kyc.approve"
    target: string;                   // Contract-supplied: e.g. "user-profile"
    outcome: string;                  // Contract-supplied: "success" / "denied"
    details?: string | null;          // Contract-supplied: optional JSON/free-text
}

interface AuditBatch {
    key: string;                      // Hex archive key, usable as cursor
    committed: boolean;               // Host-stamped: did transaction commit?
    events: AuditEvent[];
}

interface AuditPage {
    batches: AuditBatch[];
    next_cursor?: string | null;      // Present if more batches remain
}

interface GetAuditEventsOptions {
    pii_did?: string;                 // Another user's DID (as delegated agent)
    limit?: number;                   // Page size, clamped server-side
    cursor?: string;                  // next_cursor from prior page
}

// Client method signature (from index.d.ts line 1611):
class T3nClient {
    /**
     * Fetch a page of audit events. With no `pii_did`, returns the caller's own 
     * audit trail (every actor). With a `pii_did` set to another user's DID, 
     * returns — as a delegated agent — the events the caller performed for that 
     * user; admitted ONLY while that user's `agent-auth` grant to the caller 
     * is live (revocable). `cursor` is the `next_cursor` from a prior page; 
     * `limit` clamps server-side.
     *
     * Unlike getUsage, this runs the SAME session-payload encryption as 
     * executeAction: audit events carry PII (`action`/`target`/`details`), 
     * so the request and response are sealed to the session key rather than 
     * sent plaintext over TLS.
     */
    getAuditEvents(opts?: GetAuditEventsOptions): Promise<AuditPage>;
}

// Example usage: reading your own audit trail
async function readOwnAudit(client: T3nClient) {
    const firstPage: AuditPage = await client.getAuditEvents({ limit: 20 });

    for (const batch of firstPage.batches) {
        if (!batch.committed) {
            console.log("⚠️ Batch rolled back, events are unverified claims");
            continue;
        }

        for (const event of batch.events) {
            console.log({
                timestamp: new Date(event.ts_ms),
                subject: event.subject,
                actor: event.actor,
                delegationCredId: event.vc_id || "(self-call)",
                action: event.action,
                target: event.target,
                outcome: event.outcome,
                details: event.details ? JSON.parse(event.details) : null,
            });
        }
    }

    // Paginate: use next_cursor for subsequent pages
    if (firstPage.next_cursor) {
        const nextPage = await client.getAuditEvents({
            limit: 20,
            cursor: firstPage.next_cursor,
        });
        // process nextPage.batches...
    }
}

// Example: reading events you (as agent) performed for a delegated user
